function iconToDataUrl(icon: ServiceIcon): string {
  if (icon.svgMarkup) {
    return `data:image/svg+xml,${encodeURIComponent(icon.svgMarkup)}`;
  }
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="%23${icon.hex}"><path d="${icon.path}"/></svg>`;
  return `data:image/svg+xml,${svg}`;
}

interface ServiceLogoPickerProps {
  onSelect: (dataUrl: string) => void;
}

export function ServiceLogoPicker({ onSelect }: ServiceLogoPickerProps) {
  const [icons, setIcons] = useState<ServiceIcon[]>([]);
  const [loading, setLoading] = useState(true);
  const [query, setQuery] = useState("");
  const deferredQuery = useDeferredValue(query);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    import("simple-icons").then((module) => {
      const all: ServiceIcon[] = [...CUSTOM_ICONS];
      for (const v of Object.values(module)) {
        if (v != null && typeof v === "object" && "path" in v && "slug" in v) {
          const icon = v as unknown as ServiceIcon;
          all.push({
            title: icon.title,
            slug: icon.slug,
            hex: icon.hex,
            path: icon.path,
          });
        }
      }
      setIcons(all);
      setLoading(false);
    });
  }, []);

  const filtered = useMemo(() => {
    const q = deferredQuery.toLowerCase().trim();

    if (!q) {
      // Show featured first, then the rest alphabetically
      const featured: ServiceIcon[] = [];
      const rest: ServiceIcon[] = [];
      for (const icon of icons) {
        if (FEATURED_SLUGS.has(icon.slug)) {
          featured.push(icon);
        } else {
          rest.push(icon);
        }
      }
      // Sort featured by the order in FEATURED_SLUGS
      const slugOrder = Array.from(FEATURED_SLUGS);
      featured.sort(
        (a, b) => slugOrder.indexOf(a.slug) - slugOrder.indexOf(b.slug),
      );
      rest.sort((a, b) => a.title.localeCompare(b.title));
      return [...featured, ...rest];
    }

    return icons
      .filter(
        (icon) =>
          icon.title.toLowerCase().includes(q) ||
          icon.slug.toLowerCase().includes(q),
      )
      .sort((a, b) => {
        // Exact prefix matches first
        const aStarts =
          a.title.toLowerCase().startsWith(q) ||
          a.slug.toLowerCase().startsWith(q);
        const bStarts =
          b.title.toLowerCase().startsWith(q) ||
          b.slug.toLowerCase().startsWith(q);
        if (aStarts && !bStarts) return -1;
        if (!aStarts && bStarts) return 1;
        return a.title.localeCompare(b.title);
      });
  }, [icons, deferredQuery]);

  // Reset scroll when search changes
  // biome-ignore lint/correctness/useExhaustiveDependencies: intentionally trigger on deferredQuery change
  useEffect(() => {
    scrollRef.current?.scrollTo(0, 0);
  }, [deferredQuery]);

  const handleSelect = useCallback(
    (icon: ServiceIcon) => {
      onSelect(iconToDataUrl(icon));
    },
    [onSelect],
  );

  // Only render first N icons for performance, load more on scroll
  const [visibleCount, setVisibleCount] = useState(120);

  // biome-ignore lint/correctness/useExhaustiveDependencies: intentionally reset on search change
  useEffect(() => {
    setVisibleCount(120);
  }, [deferredQuery]);

  const handleScroll = useCallback(
    (e: React.UIEvent<HTMLDivElement>) => {
      const el = e.currentTarget;
      if (el.scrollTop + el.clientHeight >= el.scrollHeight - 100) {
        setVisibleCount((prev) => Math.min(prev + 120, filtered.length));
      }
    },
    [filtered.length],
  );

  const visibleIcons = filtered.slice(0, visibleCount);

  return (
    <div className="flex flex-col">
      <div className="p-2 border-b">
        <div className="relative">
          <Search className="absolute left-2 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground" />
          <Input
            placeholder="Search logos..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            className="pl-8 h-8 text-sm"
          />
        </div>
      </div>
      <div
        ref={scrollRef}
        className="overflow-y-auto p-2"
        style={{ height: 280 }}
        onScroll={handleScroll}
      >
        {loading ? (
          <div className="flex items-center justify-center h-full text-sm text-muted-foreground">
            Loading logos...
          </div>
        ) : filtered.length === 0 ? (
          <div className="flex items-center justify-center h-full text-sm text-muted-foreground">
            No logos found
          </div>
        ) : (
          <>
            {!deferredQuery && (
              <p className="text-xs text-muted-foreground px-1 pb-1.5">
                Popular services
              </p>
            )}
            <div className="grid grid-cols-6 gap-1">
              {visibleIcons.map((icon) => (
                <button
                  key={icon.slug}
                  type="button"
                  title={icon.title}
                  onClick={() => handleSelect(icon)}
                  className={cn(
                    "flex flex-col items-center gap-1 rounded-md p-1.5 hover:bg-accent transition-colors cursor-pointer",
                  )}
                >
                  {icon.svgMarkup ? (
                    <span
                      className="h-6 w-6 shrink-0 [&>svg]:h-full [&>svg]:w-full"
                      // biome-ignore lint/security/noDangerouslySetInnerHtml: static trusted SVG from CUSTOM_ICONS
                      dangerouslySetInnerHTML={{ __html: icon.svgMarkup }}
                    />
                  ) : (
                    <svg
                      role="img"
                      aria-label={icon.title}
                      viewBox="0 0 24 24"
                      fill={`#${icon.hex}`}
                      className="h-6 w-6 shrink-0"
                    >
                      <path d={icon.path} />
                    </svg>
                  )}
                  <span className="text-[10px] leading-tight text-muted-foreground truncate w-full text-center">
                    {icon.title}
                  </span>
                </button>
              ))}
            </div>
            {visibleCount < filtered.length && (
              <p className="text-xs text-muted-foreground text-center py-2">
                Scroll for more ({filtered.length - visibleCount} remaining)
              </p>
            )}
          </>
        )}
      </div>
    </div>
  );
}
